import{_ as t,o as r,c as o,a3 as a}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"67. Jury Service","description":"","frontmatter":{"title":"67. Jury Service","eba":"Biomedical Engineers 2025-2028","topics":["leave"]},"headers":[],"relativePath":"ebas/biomedical-engineers/leave/67-jury-service.md","filePath":"ebas/biomedical-engineers/leave/67-jury-service.md"}'),n={name:"ebas/biomedical-engineers/leave/67-jury-service.md"};function s(i,e,p,c,l,u){return r(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="_67-jury-service" tabindex="-1">67. Jury Service <a class="header-anchor" href="#_67-jury-service" aria-label="Permalink to &quot;67. Jury Service&quot;">​</a></h1><p>NOTE: Payments to Employees (other than casuals) for Jury Service is provided for in the NES. This clause contains supplementary terms. The Juries Act 2000 (Vic) provides further terms, including those that apply to casuals.</p><p><strong>67.1</strong> An Employee required to attend for jury service during their ordinary working hours shall be reimbursed by the Employer an amount equal to the difference between:</p><p><strong>(a)</strong> the amount paid by the state of Victoria in respect of attendance for such jury service; and</p><p><strong>(b)</strong> the amount the Employee could reasonably expect to have received from the Employer as earnings for the period at subclause 67.1(a) had they not been on jury service.</p><p><strong>67.2</strong> An Employee will notify the Employer as soon as possible of the date they are required to attend jury service.</p><p><strong>67.3</strong> The Employee will give the Employer evidence of:</p><p><strong>(a)</strong> attendance at the court;</p><p><strong>(b)</strong> the duration of such attendance; and</p><p><strong>(c)</strong> the total amount (even if it is a nil amount) of jury service pay that has been paid, or is payable, to the Employee for the period.</p><p><strong>67.4</strong> The Employee is not entitled to payment until the Employee provides evidence required by subclause 67.3.</p>',11)])])}const y=t(n,[["render",s]]);export{h as __pageData,y as default};
